  @state layouts = {  @ 16
  @state chars = {}  @ 35
  @state mgr = {  @ 49
  @state global = newScope()  @ 117
  @state prefixBuf, pendingPrefix = nil, nil  @ 181
  @state pendingPrefixNum, pendingPrefixDen = nil, nil  @ 182

